mapper.select:
/* on.standard.system.authmenu.selectLevelByMenuList */ SELECT CASE WHEN MMA.USE_YN IS NULL THEN 'N' ELSE MMA.USE_YN END AS useYn , CASE WHEN MMA.AUTH_ID IS NULL THEN #{authId} ELSE MMA.AUTH_ID END AS authId , SMMH.MENU_DIV_CD AS menuDivCd , SMMH.MENU_CD AS menuCd , SMMH.KOR_NM AS korNm , SMMH.LEVEL AS level , CONCAT( REPEAT('&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;', SMMH.LEVEL - 1), IF(SMMH.LEVEL > 1, '└ ', ''), SMMH.KOR_NM ) AS levKorNm , SMMH.URL_ADDR AS urlAddr , SMMH.MENU_CL AS menuCl , SMMH.MENU_PATH AS menuPath , MMA.READ_YN AS readYn , MMA.WRITE_YN AS writeYn , MMA.UPDATE_YN AS updateYn , MMA.DELETE_YN AS deletYn , MMA.POPUP_OPEN_YN AS popupOpenYn , MMA.POPUP_READ_YN AS popupReadYn , MMA.POPUP_WRITE_YN AS popupWiteYn , MMA.POPUP_UPDATE_YN AS popupUpdateYn , MMA.POPUP_DELETE_YN AS popupDeleteYn FROM SVI_MENU_MNG_HIERARCHY SMMH LEFT JOIN STB_M_MENU_AUTH_MNG MMA ON SMMH.MENU_CD = MMA.MENU_CD AND MMA.AUTH_ID = #{authId} WHERE SMMH.MENU_CL != 'ROOT' AND SMMH.MENU_DIV_CD = #{menuDivCd}
AND ( SMMH.KOR_NM LIKE CONCAT('%', #{searchKeyWord} ,'%') OR SMMH.ENG_NM LIKE CONCAT('%', #{searchKeyWord} ,'%') )
AND SMMH.URL_ADDR LIKE CONCAT('%', #{searchKeyWord} ,'%')
AND ( ( SMMH.KOR_NM LIKE CONCAT('%', #{searchKeyWord} ,'%') OR SMMH.ENG_NM LIKE CONCAT('%', #{searchKeyWord} ,'%') ) OR SMMH.URL_ADDR LIKE CONCAT('%', #{searchKeyWord} ,'%') )
ORDER BY SMMH.SORT_PATH

mapper.insert:
/* on.standard.system.authmenu.mergeMenuAuthMng */
INSERT INTO STB_M_MENU_AUTH_MNG (
  AUTH_ID
, MENU_CD
, READ_YN
, WRITE_YN
, UPDATE_YN
, DELETE_YN
, POPUP_OPEN_YN
, POPUP_READ_YN
, POPUP_WRITE_YN
, POPUP_UPDATE_YN
, POPUP_DELETE_YN
, USE_YN
)
VALUES

    (
      #{item.authId}
    , #{item.menuCd}
    , #{item.readYn}
    , #{item.writeYn}
    , #{item.updateYn}
    , #{item.deletYn}
    , #{item.popupOpenYn}
    , #{item.popupReadYn}
    , #{item.popupWiteYn}
    , #{item.popupUpdateYn}
    , #{item.popupDeleteYn}
    , #{item.useYn}
    )

ON DUPLICATE KEY UPDATE
   READ_YN         = VALUES(READ_YN)
, WRITE_YN         = VALUES(WRITE_YN)
, UPDATE_YN        = VALUES(UPDATE_YN)
, DELETE_YN        = VALUES(DELETE_YN)
, POPUP_OPEN_YN    = VALUES(POPUP_OPEN_YN)
, POPUP_READ_YN    = VALUES(POPUP_READ_YN)
, POPUP_WRITE_YN   = VALUES(POPUP_WRITE_YN)
, POPUP_UPDATE_YN  = VALUES(POPUP_UPDATE_YN)
, POPUP_DELETE_YN  = VALUES(POPUP_DELETE_YN)
, USE_YN           = VALUES(USE_YN);
